//! Unified transaction collection, sorting, and execution for block building.
//!
//! This module replaces the separate Phase 3b, 4, 4.5, and 5 execution loops
//! with a unified flow that:
//! 1. Collects all transactions from multiple sources
//! 2. Sorts by effective tip (tip-maximizing)
//! 3. Applies sequencing rights reordering
//! 4. Executes in the final sorted order

pub enum PreparedBundle<PoolTx: Clone + PoolTransaction> {
    Single { pool_tx, tx, tx_size, effective_gas, source },
    FulfilledAsyncPair { tx_hash, tx_for_execution, tx_size, effective_gas, settlement_tx, settlement_size, precompile_address, input, commit_block, execution_result, execution_proof },
    DeliverySettlement { origin_tx_hash, settlement_tx, effective_tip },
}

Self::Single { tx, .. } => tx
Self::FulfilledAsyncPair { tx_for_execution, .. } => tx_for_execution
Self::DeliverySettlement { settlement_tx, .. } => settlement_tx
