pub fn effective_tip_per_gas(&self, base_fee: u64) -> u128 {
    match self {
        Self::Single { tx, .. } => tx.effective_tip_per_gas(base_fee).unwrap_or(0),
        Self::FulfilledAsyncPair { tx_for_execution, .. } => Transaction::effective_tip_per_gas(tx_for_execution.tx(), base_fee).unwrap_or(0),
        Self::DeliverySettlement { effective_tip, .. } => *effective_tip,
    }
}

